diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index f9155cc66031..ef62d54254b7 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -2263,6 +2263,27 @@ static Instruction *foldSubOfMinMax(BinaryOperator &I,
     return CallInst::Create(F, {Op0, Z});
   }

+  // sub(smin/umin(X + 1, Y), smin/umin(X, Y)) --> select(X < Y, 1, 0)
+  // If X < Y: smin/umin(X+1, Y) - smin/umin(X, Y) = (X+1) - X = 1
+  // If X >= Y: smin/umin(X+1, Y) - smin/umin(X, Y) = Y - Y = 0
+  if (auto *MinMax0 = dyn_cast<MinMaxIntrinsic>(Op0))
+    if (MinMax0->getIntrinsicID() == MinMax->getIntrinsicID())
+      if (MinMax0->getRHS() == Y) {
+        Value *X1 = nullptr;
+        bool Matched = MinMax->isSigned()
+                           ? match(MinMax0->getLHS(),
+                                   m_OneUse(m_NSWAdd(m_Value(X1), m_One())))
+                           : match(MinMax0->getLHS(),
+                                   m_OneUse(m_NUWAdd(m_Value(X1), m_One())));
+        if (Matched && X1 == X) {
+          CmpInst::Predicate Pred = MinMax->isSigned() ? ICmpInst::ICMP_SLT
+                                                       : ICmpInst::ICMP_ULT;
+          Value *Cmp = Builder.CreateICmp(Pred, X, Y);
+          return SelectInst::Create(Cmp, ConstantInt::get(Ty, 1),
+                                          ConstantInt::get(Ty, 0));
+        }
+      }
+
   return nullptr;
 }

